import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.C7GIOALF.js";const p=JSON.parse('{"title":"Horde Magic: An Open Source Project","description":"","frontmatter":{},"headers":[],"relativePath":"formats/horde/sources/horde-magic-open-source-quiet-speculation.md","filePath":"formats/horde/sources/horde-magic-open-source-quiet-speculation.md","lastUpdated":1782025909000}'),i={name:"formats/horde/sources/horde-magic-open-source-quiet-speculation.md"};function l(s,e,n,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="horde-magic-an-open-source-project" tabindex="-1">Horde Magic: An Open Source Project <a class="header-anchor" href="#horde-magic-an-open-source-project" aria-label="Permalink to &quot;Horde Magic: An Open Source Project&quot;">​</a></h1><p>Source: <a href="https://www.quietspeculation.com/2011/10/horde-magic-an-open-source-project/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2011/10/horde-magic-an-open-source-project/</a></p><p>Author: Peter Knudson<br> Published: October 26, 2011</p><p>This follow-up article treats Horde Magic as an open-source casual format. It gathers early community feedback, discusses scaling and planeswalkers, introduces preconstructed Survivor decks, shares alternate Horde deck ideas, and proposes a first banned list.</p><h2 id="main-design-point" tabindex="-1">Main Design Point <a class="header-anchor" href="#main-design-point" aria-label="Permalink to &quot;Main Design Point&quot;">​</a></h2><p>The article argues that the format should be easy to change. If the Zombie Horde is too easy or too hard, the first lever should usually be the Horde deck itself rather than making the rules more complicated.</p><h2 id="scaling-problems" tabindex="-1">Scaling Problems <a class="header-anchor" href="#scaling-problems" aria-label="Permalink to &quot;Scaling Problems&quot;">​</a></h2><p>Some players found the Horde too easy with more Survivors. The article suggests reducing setup turns for 3-4 player games from three turns to two.</p><p>The author prefers preserving the simple rules engine and increasing difficulty through card selection:</p><ul><li>Remove weak Horde cards.</li><li>Add more threatening non-token cards.</li><li>Include better sweepers or reset effects.</li><li>Tune the Horde deck to the Survivor decks being used.</li></ul><h2 id="suggested-horde-additions" tabindex="-1">Suggested Horde Additions <a class="header-anchor" href="#suggested-horde-additions" aria-label="Permalink to &quot;Suggested Horde Additions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card</th><th>Reason</th></tr></thead><tbody><tr><td>Noxious Ghoul</td><td>Flavorful Zombie sweeper.</td></tr><tr><td>All Is Dust</td><td>Broad reset effect that punishes overbuilt defenses.</td></tr><tr><td>Smallpox</td><td>Early disruption; sacrifice choices can be handled simply.</td></tr><tr><td>Mnemonic Nexus</td><td>Can refill the Horde late and create a surprise reset.</td></tr><tr><td>Vulturous Zombie</td><td>Adds a large flying threat.</td></tr><tr><td>Living Death</td><td>Flavorful, swingy board reset.</td></tr></tbody></table><h2 id="planeswalker-rule" tabindex="-1">Planeswalker Rule <a class="header-anchor" href="#planeswalker-rule" aria-label="Permalink to &quot;Planeswalker Rule&quot;">​</a></h2><p>The original article did not handle planeswalkers cleanly.</p><p>The proposed solution:</p><ol><li>If Survivors control one or more planeswalkers, flip a coin at the beginning of Horde combat.</li><li>On heads, the Horde randomly allocates attackers to planeswalkers.</li><li>Allocate one Zombie per point of loyalty for each planeswalker, starting in random planeswalker order if there are multiple.</li></ol><p>This is not elegant, but it gives planeswalkers risk without making the Horde too decision-heavy.</p><h2 id="preconstructed-survivor-decks" tabindex="-1">Preconstructed Survivor Decks <a class="header-anchor" href="#preconstructed-survivor-decks" aria-label="Permalink to &quot;Preconstructed Survivor Decks&quot;">​</a></h2><p>The article suggests building fixed Survivor Commander decks designed to fight the Horde. These could work like party roles: Fighter, Cleric, Wizard, and so on.</p><p>The included example is a green-white Survivor deck by <code>@mtgcolorpie</code>, with <strong>Tolsimir Wolfblood</strong> as commander. The article likes it because it is thematic, not overpowered, and full of defensive / soldier-flavored cards.</p><h2 id="alternate-horde-deck-ideas" tabindex="-1">Alternate Horde Deck Ideas <a class="header-anchor" href="#alternate-horde-deck-ideas" aria-label="Permalink to &quot;Alternate Horde Deck Ideas&quot;">​</a></h2><p>The article collects several community Horde concepts.</p><h3 id="sliver-horde" tabindex="-1">Sliver Horde <a class="header-anchor" href="#sliver-horde" aria-label="Permalink to &quot;Sliver Horde&quot;">​</a></h3><p>Credit: <code>@wobbles</code></p><p>The Sliver Horde uses small Slivers that become more dangerous as lords accumulate. The article notes that Sliver Overlord could be placed at the bottom of the deck to create an end-boss feeling.</p><h3 id="cat-horde" tabindex="-1">Cat Horde <a class="header-anchor" href="#cat-horde" aria-label="Permalink to &quot;Cat Horde&quot;">​</a></h3><p>Credit: <code>d0su</code> from MTG Salvation</p><p>Cat tokens are close to Zombie tokens in baseline stats, which makes them easier to adapt. The deck mixes mediocre cats, larger threats, and multicolor finishers.</p><h3 id="merfolk-horde" tabindex="-1">Merfolk Horde <a class="header-anchor" href="#merfolk-horde" aria-label="Permalink to &quot;Merfolk Horde&quot;">​</a></h3><p>Credit: <code>@Bassiuz</code></p><p>The Merfolk Horde uses smaller tokens but leans on lords and disruptive blue-white effects. The article calls out cards such as Hysterical Blindness, Summon the School, and Balance as examples of collection finds that can become Horde cards.</p><h2 id="proposed-survivor-ban-list" tabindex="-1">Proposed Survivor Ban List <a class="header-anchor" href="#proposed-survivor-ban-list" aria-label="Permalink to &quot;Proposed Survivor Ban List&quot;">​</a></h2><p>The article proposes banning cards that automatically break the Horde. These are not presented as a polished final ban list, but as a starting point.</p><ul><li>Aether Flash</li><li>Aurification</li><li>Barbed Foliage</li><li>Caltrops</li><li>Crawlspace</li><li>Dueling Grounds</li><li>Arteeoh, Dread Scavenger</li><li>Elesh Norn, Grand Cenobite</li><li>Ensnaring Bridge</li><li>Eradicate</li><li>Grindstone</li><li>Haunting Echoes</li><li>Island Sanctuary</li><li>Lethal Vapors</li><li>Leyline of Singularity</li><li>Magus of the Moat</li><li>Mind Funeral</li><li>Moat</li><li>No Mercy</li><li>Platinum Angel</li><li>Platinum Emperion</li><li>Silent Arbiter</li><li>Solitary Confinement</li><li>Stormtide Leviathan</li><li>Surgical Extraction</li><li>Tainted Aether</li><li>Teferi&#39;s Moat</li><li>Time Stretch</li><li>Trepanation Blade</li></ul><h2 id="takeaways-for-game-night-boxes" tabindex="-1">Takeaways For Game-Night Boxes <a class="header-anchor" href="#takeaways-for-game-night-boxes" aria-label="Permalink to &quot;Takeaways For Game-Night Boxes&quot;">​</a></h2><p>This article is especially useful for boxed-set design because it opens the door to:</p><ul><li>Tuning difficulty by changing the Horde deck.</li><li>Building class-like Survivor decks.</li><li>Creating themed Horde boxes beyond Zombies.</li><li>Maintaining a matchup-specific ban/watch list.</li><li>Treating Horde Magic as a flexible engine rather than one fixed ruleset.</li></ul>',37)])])}const m=a(i,[["render",l]]);export{p as __pageData,m as default};
